scwin.getAcctDeptCd = async function (newYear, acctDeptCd) {
  // SELECT 절 
  var param1 = " ACCT_DEPT_CD   as COL1 " + ",ACCT_DEPT_CD   as COL2 " + ",''   		as COL3 " + ",''   		as COL4 " + ",''  		as COL5 " + ",'' 			as COL6 " + ",'' 			as COL7 " + ",'' 			as COL8 " + ",'' 			as COL9 " + ",'' 			as COL10 ";

  // 대상테이블 	
  var param2 = "(SELECT * FROM TB_CO011 WHERE ACCT_YEAR = SUBSTR('" + newYear + "',1,4))" + "  START  WITH ACCT_DEPT_CD = ( " + "                                 SELECT UPPER_ACCT_DEPT_CD " + "                                   FROM TB_CO011 " + "                                  WHERE ACCT_YEAR = SUBSTR('" + newYear + "',1,4)" + "                                    AND ACCT_DEPT_CD = '" + acctDeptCd + "'" + "							 ) " + "  CONNECT BY PRIOR ACCT_DEPT_CD = UPPER_ACCT_DEPT_CD ";

  // 조건절	  
  //var param3 = 						  
  //	   " AND 1=1 "
  ;

  // 정렬    
  var param4 = " ACCT_DEPT_CD ";

  /*        
  ds_bizdiv.DataId = 
      "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest3" + "&param1=" + param1 
                                                                                  + "&param2=" + param2
                                                                                  + "&param4=" + param4;		
  ds_bizdiv.Reset();
  */

  dma_bizdiv.set("sysCd", "CommonEBC");
  dma_bizdiv.set("queryId", "dinymicQueryTest3");
  dma_bizdiv.set("param1", param1);
  dma_bizdiv.set("param2", param2);
  dma_bizdiv.set("param4", param4);
  ds_bizdiv.removeAll();

  //submit 처리.
  let objSubmit = await $c.sbm.execute($p, sbm_bizdiv);
  if (objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {
    await scwin.sbm_bizdiv_submitdone();
  }
};
